# Vantro Card-on-Signup patch
# Updates checkout route with 30-day trial + webhook handlers

$ErrorActionPreference = "Stop"

Write-Host "Writing C:\vantro\app\api\billing\checkout\route.ts..." -ForegroundColor Cyan
$b64_app_api_billing_checkout_route_ts = ""
[System.IO.File]::WriteAllBytes("C:\vantro\app\api\billing\checkout\route.ts", [System.Convert]::FromBase64String($b64_app_api_billing_checkout_route_ts))

Write-Host "Writing C:\vantro\app\api\billing\webhook\route.ts..." -ForegroundColor Cyan
$b64_app_api_billing_webhook_route_ts = ""
[System.IO.File]::WriteAllBytes("C:\vantro\app\api\billing\webhook\route.ts", [System.Convert]::FromBase64String($b64_app_api_billing_webhook_route_ts))

Write-Host ""
Write-Host "Done. Now run from C:\vantro:" -ForegroundColor Green
Write-Host "  git add ."
Write-Host "  git commit -m 'feat(billing): card-on-signup with 30-day Stripe trial'"
Write-Host "  git push origin master"